public class AssetsAssetOperateApplyController extends BaseController {    @Resource    private IAssetsAssetOperateApplyService AssetsAssetOperateApplyService;    @Operation(summary = "查询数据资产操作申请列表")    @PreAuthorize("@ss.hasPermi('da:assetOperateApply:list')")    @GetMapping("/list")    public CommonResult<PageResult<AssetsAssetOperateApplyRespVO>> list(AssetsAssetOperateApplyPageReqVO AssetsAssetOperateApply) {        PageResult<AssetsAssetOperateApplyDO> page = AssetsAssetOperateApplyService.getDaAssetOperateApplyPage(AssetsAssetOperateApply);        return CommonResult.success(BeanUtils.toBean(page, AssetsAssetOperateApplyRespVO.class));    }    @Operation(summary = "导出数据资产操作申请列表")    @PreAuthorize("@ss.hasPermi('da:assetOperateApply:export')")    @Log(title = "数据资产操作申请", businessType = BusinessType.EXPORT)    @PostMapping("/export")    public void export(HttpServletResponse response, AssetsAssetOperateApplyPageReqVO exportReqVO) {        exportReqVO.setPageSize(PageParam.PAGE_SIZE_NONE);        List<AssetsAssetOperateApplyDO> list = (List<AssetsAssetOperateApplyDO>) AssetsAssetOperateApplyService.getDaAssetOperateApplyPage(exportReqVO).getRows();        ExcelUtil<AssetsAssetOperateApplyRespVO> util = new ExcelUtil<>(AssetsAssetOperateApplyRespVO.class);        util.exportExcel(response, AssetsAssetOperateApplyConvert.INSTANCE.convertToRespVOList(list), "应用管理数据");    }    @Operation(summary = "导入数据资产操作申请列表")    @PreAuthorize("@ss.hasPermi('da:assetOperateApply:import')")    @Log(title = "数据资产操作申请", businessType = BusinessType.IMPORT)    @PostMapping("/importData")    public AjaxResult importData(MultipartFile file, boolean updateSupport) throws Exception {        ExcelUtil<AssetsAssetOperateApplyRespVO> util = new ExcelUtil<>(AssetsAssetOperateApplyRespVO.class);        List<AssetsAssetOperateApplyRespVO> importExcelList = util.importExcel(file.getInputStream());        String operName = getUsername();        String message = AssetsAssetOperateApplyService.importDaAssetOperateApply(importExcelList, updateSupport, operName);        return success(message);    }    @Operation(summary = "获取数据资产操作申请详细信息")    @PreAuthorize("@ss.hasPermi('da:assetOperateApply:query')")    @GetMapping(value = "/{id}")    public CommonResult<AssetsAssetOperateApplyRespVO> getInfo(@PathVariable("id") Long id) {        AssetsAssetOperateApplyDO AssetsAssetOperateApplyDO = AssetsAssetOperateApplyService.getDaAssetOperateApplyById(id);        return CommonResult.success(BeanUtils.toBean(AssetsAssetOperateApplyDO, AssetsAssetOperateApplyRespVO.class));    }    @Operation(summary = "新增数据资产操作申请")    @PreAuthorize("@ss.hasPermi('da:assetOperateApply:add')")    @Log(title = "数据资产操作申请", businessType = BusinessType.INSERT)    @PostMapping    public CommonResult<Long> add(@Valid @RequestBody AssetsAssetOperateApplySaveReqVO AssetsAssetOperateApply) {        AssetsAssetOperateApply.setCreatorId(getUserId());        AssetsAssetOperateApply.setCreateBy(getNickName());        AssetsAssetOperateApply.setCreateTime(DateUtil.date());        return CommonResult.toAjax(AssetsAssetOperateApplyService.createDaAssetOperateApply(AssetsAssetOperateApply));    }    @Operation(summary = "修改数据资产操作申请")    @PreAuthorize("@ss.hasPermi('da:assetOperateApply:edit')")    @Log(title = "数据资产操作申请", businessType = BusinessType.UPDATE)    @PutMapping    public CommonResult<Integer> edit(@Valid @RequestBody AssetsAssetOperateApplySaveReqVO AssetsAssetOperateApply) {        AssetsAssetOperateApply.setUpdatorId(getUserId());        AssetsAssetOperateApply.setUpdateBy(getNickName());        AssetsAssetOperateApply.setUpdateTime(DateUtil.date());        return CommonResult.toAjax(AssetsAssetOperateApplyService.updateDaAssetOperateApply(AssetsAssetOperateApply));    }    @Operation(summary = "删除数据资产操作申请")    @PreAuthorize("@ss.hasPermi('da:assetOperateApply:remove')")    @Log(title = "数据资产操作申请", businessType = BusinessType.DELETE)    @DeleteMapping("/{ids}")    public CommonResult<Integer> remove(@PathVariable Long[] ids) {        return CommonResult.toAjax(AssetsAssetOperateApplyService.removeDaAssetOperateApply(Arrays.asList(ids)));    }}